interface GooglePhotosEmbedderAppProps {
    onBack: () => void;
    user: User | null;
    history: GPhotosHistoryItem[];
}

const GooglePhotosEmbedderApp: React.FC<GooglePhotosEmbedderAppProps> = ({ onBack, user, history: firebaseHistory }) => {
    const [googlePhotosUrl, setGooglePhotosUrl] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [isCopied, setIsCopied] = useState<{ [key: string]: boolean }>({});
    const [fullPreviewUrl, setFullPreviewUrl] = useState<string | null>(null);
    const [guestHistory, setGuestHistory] = useState<GPhotosHistoryItem[]>([]);
    const [viewedHistoryItem, setViewedHistoryItem] = useState<GPhotosHistoryItem | null>(null);
    const historyViewRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!user) {
            try {
                const storedHistory = localStorage.getItem(LOCAL_STORAGE_KEY);
                if (storedHistory) {
                    setGuestHistory(JSON.parse(storedHistory));
                }
            } catch (e) {
                console.error("Failed to parse history from localStorage", e);
                setGuestHistory([]);
            }
        }
    }, [user]);

    const history = user ? firebaseHistory : guestHistory;

    useEffect(() => {
        if (viewedHistoryItem) {
            setTimeout(() => {
                historyViewRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }, 100);
        }
    }, [viewedHistoryItem]);

    const resetState = () => {
        setError('');
        setIsCopied({});
        setViewedHistoryItem(null);
    };

    const handleGenerate = async (e: React.FormEvent) => {
        e.preventDefault();
        resetState();
        setIsLoading(true);

        if (!googlePhotosUrl || !googlePhotosUrl.startsWith('https://photos.app.goo.gl/')) {
            setError('Please enter a valid Google Photos share URL.');
            setIsLoading(false);
            return;
        }

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 15000); 

        try {
            const urlToProxy = new URL(googlePhotosUrl);
            urlToProxy.searchParams.set('_cache', Date.now().toString());
            const proxyUrl = `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(urlToProxy.toString())}`;

            const response = await fetch(proxyUrl, { signal: controller.signal });
            clearTimeout(timeoutId);

            if (!response.ok) {
                throw new Error(`Proxy service returned an error: ${response.status}`);
            }

            const htmlContent = await response.text();
            if (!htmlContent) {
                throw new Error('Proxy service did not return any content.');
            }

            // Extract album title
            const titleMatch = htmlContent.match(/<title>([^<]+)<\/title>/);
            const albumTitle = titleMatch ? titleMatch[1].replace(' - Google Photos', '').trim() : `Album from ${new Date().toLocaleDateString()}`;

            // Advanced metadata extraction
            // Google Photos shared pages contain JSON data in scripts (AF_initDataCallback)
            // Filenames are often present in arrays alongside image IDs.
            const extractedFiles: { url: string; filename: string }[] = [];

            // Regex to find image base URLs
            const imageBaseUrlRegex = /"(https:\/\/lh3\.googleusercontent\.com\/(?:pw\/|d\/)?[a-zA-Z0-9\-_]{40,})[^"]*"/g;
            const matches = Array.from(htmlContent.matchAll(imageBaseUrlRegex)).map(m => m[1]);
            const uniqueUrls = Array.from(new Set(matches));

            // Best-effort filename scraping: search for script blocks containing filenames
            // We search for patterns like: [null,"FILENAME.JPG",null,null,null,null,null,null,"lh3.googleusercontent.com..."]
            // This is brittle but can work on some shared album structures.
            const filenamePattern = /"([^"]+\.(?:jpg|jpeg|png|webp|gif|mp4|mov))"/gi;
            const foundFilenames = Array.from(new Set(Array.from(htmlContent.matchAll(filenamePattern)).map(m => m[1])));

            uniqueUrls.forEach((baseUrl, index) => {
                // Since matching filenames to URLs purely via regex is imprecise without full JSON parsing,
                // we'll attempt a zip approach or sequential fallback.
                const filename = (foundFilenames.length > index) 
                    ? foundFilenames[index] 
                    : `${albumTitle} - Photo ${index + 1}.jpg`;

                extractedFiles.push({ url: baseUrl, filename });
            });

            if (extractedFiles.length === 0) {
                 // Fallback to og:image if nothing else was found
                 const ogImageMatch = htmlContent.match(/<meta\s+property="og:image"\s+content="([^"]+)"/);
                 if (ogImageMatch && ogImageMatch[1]) {
                    const baseUrl = ogImageMatch[1].split('=')[0];
                    extractedFiles.push({ url: baseUrl, filename: `${albumTitle}.jpg` });
                 }
            }

            if (extractedFiles.length === 0) {
                 throw new Error('Could not extract any images. Ensure the link is valid and public.');
            }

            const photoResults: PhotoResult[] = extractedFiles.map((item, index) => {
                const highResUrl = `${item.url}=w2400`;
                const previewUrl = `${item.url}=w600`;
                const uniqueId = `gphoto-embed-${Date.now()}-${index}`;
                const filename = item.filename;

